import React from "react";
import { Route } from "@/types/route";
import { Link } from "react-router-dom";

// .routeCard {
//   display: flex;
//   justify-content: space-between;
//   background: white;
//   border-radius: 12px;
//   padding: 18px;
//   text-decoration: none;
//   color: inherit;
//   border-left: 6px solid #003057;
//   box-shadow: 0 2px 8px rgba(0,0,0,0.08);
//   transition: transform 0.2s ease, box-shadow 0.2s ease;
// }

const routeCardStyle: React.CSSProperties = {
  display: "flex",
  justifyContent: "space-between",
  background: "white",
  borderRadius: "12px",
  padding: "18px",
  textDecoration: "none",
  color: "inherit",
  borderLeft: "6px solid #003057",
  boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
  transition: "transform 0.2s ease, box-shadow 0.2s ease",
};

// .routeCard:hover {
//   transform: translateY(-4px);
//   box-shadow: 0 8px 20px rgba(0,0,0,0.15);
// }

// Hover effect style
const routeCardHoverStyle: React.CSSProperties = {
  transform: "translateY(-4px)",
  boxShadow: "0 8px 20px rgba(0,0,0,0.15)",
};

// .gold {
//   border-left-color: #b3a369;
// }

const goldBorderStyle: React.CSSProperties = {
  borderLeftColor: "#B3A369",
};

// .red {
//   border-left-color: #d11c1c;
// }

const redBorderStyle: React.CSSProperties = {
  borderLeftColor: "#d11c1c",
};

// .defaultRoute {
//   border-left-color: #003057;
// }

const defaultBorderStyle: React.CSSProperties = {
  borderLeftColor: "#003057",
};

// .routeInfo {
//   display: flex;
//   flex-direction: column;
//   gap: 12px;
// }

const routeInfoStyle: React.CSSProperties = {
  display: "flex",
  flexDirection: "column",
  gap: "12px",
};

// .routeHeader {
//   display: flex;
//   align-items: center;
//   gap: 10px;
// }

const routeHeaderStyle: React.CSSProperties = {
  display: "flex",
  alignItems: "center",
  gap: "10px",
};

// .routeName {
//   font-size: 20px;
//   font-weight: 700;
//   color: #003057;
//   margin: 0;
// }

const routeNameStyle: React.CSSProperties = {
  fontSize: "20px",
  fontWeight: 700,
  color: "#003057",
  margin: 0,
};

// .badge {
//   padding: 4px 10px;
//   background: #d4edda;
//   color: #155724;
//   border-radius: 12px;
//   font-size: 10px;
//   font-weight: 600;
// }

const routeBadgeStyle: React.CSSProperties = {
  padding: "4px 10px",
  backgroundColor: "#d4edda",
  color: "#155724",
  borderRadius: "12px",
  fontSize: "10px",
  fontWeight: 600,
};

// .routeDetails {
//   display: flex;
//   flex-direction: column;
//   gap: 6px;
//   font-size: 14px;
// }

const routeDetailsStyle: React.CSSProperties = {
  display: "flex",
  flexDirection: "column",
  gap: "6px",
  fontSize: "14px",
};

// .detailItem strong {
//   color: #003057;
// }

const detailItemStyle: React.CSSProperties = {
  color: "#003057",
};

// .routeArrow {
//   font-size: 24px;
//   color: #ccc;
//   align-self: center;
// }

const routeArrowStyle: React.CSSProperties = {
  fontSize: "24px",
  color: "#ccc",
  alignSelf: "center",
};

interface Props {
  route: Route;
}

const RouteCard: React.FC<Props> = ({ route }) => {
  // Map route color → CSS class
  const colorClass = route.name.toLowerCase().includes("gold")
    ? goldBorderStyle
    : route.name.toLowerCase().includes("red")
    ? redBorderStyle
    : defaultBorderStyle;

  return (
    <Link
      to={`/bus-routes?routeId=${route.id}`}
      style={{ ...routeCardStyle, ...colorClass }}
    >
      <div style={routeInfoStyle}>
        <div style={routeHeaderStyle}>
          <h2 style={routeNameStyle}>{route.name}</h2>
          <span style={routeBadgeStyle}>Active</span>
        </div>

        <div style={routeDetailsStyle}>
          <div style={detailItemStyle}>
            <strong>📍 Stops:</strong> {route.stops.length}
          </div>
          <div style={detailItemStyle}>
            <strong>🚌 Buses:</strong> {route.busLocations?.length ?? 0}
          </div>
          <div style={detailItemStyle}>
            <strong>⏱ Avg Delay:</strong> +2 min
          </div>
        </div>
      </div>

      <div style={routeArrowStyle}>→</div>
    </Link>
  );
};

export default RouteCard;
